effect.shader:
void main() {
    vec4 frontColor = texture2DCv(inputImg.texture,acScreenNorm);
    vec4 backColor = color * alpha;
    if( !screenSpace ) {
        float insideLayer = step(0.0,acLayerNorm.x) * step(acLayerNorm.x,1.0) * step(0.0,acLayerNorm.y) * step(acLayerNorm.y,1.0);
        backColor *= insideLayer;
    }
    if( punchout ) {
        gl_FragColor = backColor*(1.-frontColor.a);
    } else {
        gl_FragColor = backColor*(1.-frontColor.a)+frontColor;
    }
}
